code.JavaScript:
class LinkedList {
    constructor() {
        this.head = null;
    }

    insertAfterK(value, k) {
        const newNode = new Node(value);

        if (this.head === null) {
            this.head = newNode;
            return;
        }

        let current = this.head;

        if (k === 0) {
            newNode.next = this.head;
            this.head = newNode;
            return;
        }

        for (let i = 1; i < k; i++) {
            if (current.next === null) break;
            current = current.next;
        }

        newNode.next = current.next;
        current.next = newNode;
    }
}
